with open("frontend/pages/study.html", "w", encoding="utf-8") as f:
    f.write("""<!DOCTYPE html><html><head><meta charset="UTF-8"><title>Study - EPRA</title><link rel="stylesheet" href="../css/style.css"></head><body><nav class="navbar"><h2>Study Mode</h2><a href="dashboard.html" class="btn btn-outline">Back</a></nav><div class="exam-container"><h2 style="text-align:center;color:#1a237e">Study Materials</h2><p style="text-align:center;margin:10px 0">Review questions with answers and explanations</p><div id="content"><p style="text-align:center;padding:50px">Loading questions...</p></div></div><script>var t=localStorage.getItem("access_token");if(!t)location.href="login.html";var url="http://localhost:5000/api/questions?limit=10&include_answer=true";fetch(url,{headers:{"Authorization":"Bearer "+t}}).then(function(r){return r.json()}).then(function(d){if(!d.questions||d.questions.length===0){document.getElementById("content").innerHTML="<p style=text-align:center;color:red>No questions found. Run seed_data.py first!</p>";return}var h="";d.questions.forEach(function(q,i){h+="<div class=question-box><h3>Q"+(i+1)+": "+q.question_text+"</h3><p><b>Category:</b> "+q.category+" | <b>Regulation:</b> "+(q.regulation_reference||"N/A")+"</p><button class=btn-primary onclick=document.getElementById(\"a"+i+"\").style.display=\"block\";this.style.display=\"none\">Show Answer</button><div id=a"+i+" style=\"display:none;margin-top:10px;padding:15px;background:#e8f5e9;border-radius:8px\"><p><b>Answer:</b> "+q.correct_answer+"</p><p><b>Explanation:</b> "+(q.explanation||"N/A")+"</p>"+(q.practical_tip?"<p><b>Field Tip:</b> "+q.practical_tip+"</p>":"")+"</div></div>"});document.getElementById("content").innerHTML=h}).catch(function(e){document.getElementById("content").innerHTML="<p style=text-align:center;color:red>Error: "+e.message+". Is the server running?</p>"});</script></body></html>""")

with open("frontend/pages/exam.html", "w", encoding="utf-8") as f:
    f.write("""<!DOCTYPE html><html><head><meta charset="UTF-8"><title>Exam - EPRA</title><link rel="stylesheet" href="../css/style.css"></head><body><nav class="navbar"><h2>Exam Mode</h2><a href="dashboard.html" class="btn btn-outline">Back</a></nav><div class="exam-container"><h2 style="text-align:center">EPRA Exam Simulation</h2><div class="timer">Time: <span id="timer">60:00</span></div><button id="startBtn" class="btn btn-primary" style="display:block;margin:20px auto">Start Exam</button><div id="qArea" style="display:none"></div><button id="submitBtn" class="btn btn-primary" style="display:none;margin:20px auto">Submit Exam</button></div><script>var qs=[],ci=0,ans={},tl=3600,ti,eid;var t=localStorage.getItem("access_token");if(!t)location.href="login.html";document.getElementById("startBtn").addEventListener("click",function(){fetch("http://localhost:5000/api/exam/start",{method:"POST",headers:{"Authorization":"Bearer "+t,"Content-Type":"application/json"},body:JSON.stringify({total_questions:5})}).then(function(r){return r.json()}).then(function(d){if(!d.questions){alert(d.error);return}qs=d.questions;eid=d.exam_id;document.getElementById("startBtn").style.display="none";document.getElementById("submitBtn").style.display="block";showQ();ti=setInterval(function(){tl--;var m=Math.floor(tl/60),s=tl%60;document.getElementById("timer").textContent=m+":"+(s<10?"0":"")+s;if(tl<=0)submitE()},1000)}).catch(function(e){alert("Server error: "+e.message)})});function showQ(){if(ci>=qs.length){submitE();return}var q=qs[ci];var h="<div class=question-box><h3>Question "+(ci+1)+" of "+qs.length+"</h3><p style=font-size:1.2rem;margin:20px>"+q.question_text+"</p>";q.options.forEach(function(o,i){h+="<div class=option"+(ans[q.id]===o?" selected":"")+" onclick=sel("+q.id+',&quot;'+o.replace(/"/g,"&quot;")+"&quot;)>"+(i+1)+". "+o+"</div>"});h+="</div><div style=display:flex;gap:10px;justify-content:center;margin-top:20px>";if(ci>0)h+="<button class=\"btn btn-outline\" onclick=prevQ()>Previous</button>";h+="<button class=\"btn btn-primary\" onclick=nextQ()>"+(ci<qs.length-1?"Next":"Finish Exam")+"</button></div>";document.getElementById("qArea").innerHTML=h;document.getElementById("qArea").style.display="block"}function sel(id,o){ans[id]=o;showQ()}function nextQ(){ci++;showQ()}function prevQ(){ci--;showQ()}function submitE(){clearInterval(ti);document.getElementById("qArea").innerHTML="<div class=question-box style=text-align:center><h2>Submitting...</h2></div>";fetch("http://localhost:5000/api/exam/submit",{method:"POST",headers:{"Authorization":"Bearer "+t,"Content-Type":"application/json"},body:JSON.stringify({exam_id:eid,answers:ans,time_taken:3600-tl})}).then(function(r){return r.json()}).then(function(d){document.getElementById("qArea").innerHTML="<div class=question-box style=text-align:center><h2>Exam Complete!</h2><p style=font-size:4rem;color:"+(d.passed?"green":"red")+">"+d.percentage+"%</p><p style=font-size:1.5rem>"+d.score+" out of "+d.total+" correct</p><p style=font-size:1.2rem>"+(d.passed?"PASSED! Great job!":"Keep practicing!")+"</p><a href=dashboard.html class=btn-primary style=margin-top:20px>Back to Dashboard</a></div>";document.getElementById("submitBtn").style.display="none"}).catch(function(e){document.getElementById("qArea").innerHTML="<p style=color:red>Error: "+e.message+"</p>"})}</script></body></html>""")

print("Both pages fixed successfully!")
